package STARTER.DTOs;import STARTER.Utils.ValidationPatterns;import jakarta.validation.constraints.AssertTrue;import jakarta.validation.constraints.NotBlank;import jakarta.validation.constraints.Pattern;import jakarta.validation.constraints.Size;import lombok.*;@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Builderpublic class UserDTO {    @NotBlank(message = "Username is required")    @Size(min = 3, max = 30, message = "Username must be between 3 and 30 characters")    @Pattern(            regexp = ValidationPatterns.USERNAME,            message = "Username must start with a letter and contain only letters, numbers, or underscore"    )    private String username;    @NotBlank(message = "Email is required")    @Pattern(            regexp = ValidationPatterns.EMAIL,            message = "Email must be in format name@domain.com"    )    private String email;    @NotBlank(message = "Password is required")    @Size(min = 8, max = 64, message = "Password must be between 8 and 64 characters")    @Pattern(            regexp = ValidationPatterns.PASSWORD,            message = "Password must include an uppercase letter, a lowercase letter, a digit, and a special character"    )    private String password;    @NotBlank(message = "Confirm password is required")    @Size(min = 8, max = 64, message = "Password must be between 8 and 64 characters")    private String confirmPassword;    @AssertTrue(message = "Passwords do not match")    public boolean isPasswordConfirmMatching() {        if (password == null || confirmPassword == null) {            return true;        }        return password.equals(confirmPassword);    }}